function or() {
  const parsers = [...arguments];
  return (input) => {
    // console.log('xcxc or: ', input.slice(0,LOG_HEAD));

    for (var i = 0; i < parsers.length; i++) {
      const res = parsers[i](input);

      if (res) return res;
    }

    return null;
  };
}

function many(parser) {
  function recur(input, partial) {
    const res = parser(trimWS(input));
    if (res) return recur(res.rest, partial.concat([res.result]));
    return { result: partial, rest: input };
  }

  return (input) => {
    // console.log('xcxc many: ', input.slice(0,LOG_HEAD));
    return recur(input, []);
  };
}

function oneOrMore(parser) {
  return seq(parser, many(parser));
}

const empty = (input) => ({
  result: [],
  rest: input,
});

const fail = (input) => null;

const opt = (parser) => or(
  parser,
  empty
);

